import numpy as np

# Simulated pre-encoded vectors from BGE-M3
query_dense = np.array([0.8, 0.6, 0.1])
doc_dense = np.array([[0.7, 0.5, 0.2], [0.1, 0.3, 0.9]])

# Dense: cosine similarity
def cosine(a, b):
    return float(np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b)))

dense_scores = [cosine(query_dense, d) for d in doc_dense]
print(f"Dense scores: {[round(s, 3) for s in dense_scores]}")

# Sparse: dot product of shared token weights
q_sparse = {"GIL": 0.9, "parallel": 0.7, "block": 0.5}
d_sparse = [{"GIL": 0.8, "thread": 0.6}, {"async": 0.9, "IO": 0.7}]

def sparse_score(q, d):
    return sum(q[k] * d[k] for k in set(q) & set(d))

sparse_scores = [sparse_score(q_sparse, d) for d in d_sparse]
print(f"Sparse scores: {sparse_scores}")

# Fuse: weighted combination
def fuse(dense_s, sparse_s, w_d=0.5, w_s=0.5):
    return [w_d * d + w_s * s for d, s in zip(dense_s, sparse_s)]

final = fuse(dense_scores, sparse_scores)
for i, score in enumerate(final):
    print(f"Doc {i}: {score:.3f}")
